// src/repositories/StudyMethodRepository.js
import StudyMethodDAO from '../dao/StudyMethodDAO';

const StudyMethodRepository = {
  async getAll() {
    return await StudyMethodDAO.findAll();
  },

  async getById(id) {
    return await StudyMethodDAO.findById(id);
  },

  async create(data) {
    return await StudyMethodDAO.create(data);
  },

  async update(id, data) {
    return await StudyMethodDAO.update(id, data);
  },

  async remove(id) {
    return await StudyMethodDAO.delete(id);
  },

  async getByCategory(category) {
    return await StudyMethodDAO.findByCategory(category);
  },

  async search(term) {
    return await StudyMethodDAO.search(term);
  }
};

export default StudyMethodRepository;
